1	import { PlayCircleOutlined } from '@ant-design/icons';
2	import { App, Alert, Button, Card, Empty, Flex, List, Spin, Tag, Tooltip, Typography } from 'antd';
3	import { useState } from 'react';
4	import { useNavigate, useParams } from 'react-router-dom';
5	
6	import {
7	  CONNECTION_KIND,
8	  CONNECTION_TYPE_LABELS,
9	  type Connection,
10	  ENV_COLORS,
11	  envLabel,
12	  listConnections,
13	} from '../api/connections';
14	import {
15	  canManageSuite,
16	  canRunSuite,
17	  type Check,
18	  deleteCheck,
19	  deleteSuite,
