24	} from '../api/suites';
25	import { CheckDrawer } from '../components/checks/CheckDrawer';
26	import { ConnectionTypeAvatar } from '../components/connections/connectionVisuals';
27	import { LiveRunProgress } from '../components/runs/LiveRunProgress';
28	import { ImportSuiteDrawer } from '../components/suites/ImportSuiteDrawer';
29	import { SchedulesPanel } from '../components/suites/SchedulesPanel';
30	import { SharePanel } from '../components/suites/SharePanel';
31	import { SuiteDrawer } from '../components/suites/SuiteDrawer';
32	import { TriggersPanel } from '../components/suites/TriggersPanel';
33	import { BRAND } from '../theme';
34	import { downloadJson, toFilenameStem } from '../utils/download';
35	import { type AsyncState, useAsyncData } from '../hooks/useAsyncData';
36	import { useRunTrigger } from '../hooks/useRunTrigger';
37	
38	/**
39	 * A suite's identity block — datasource avatar + name + connection/env — shared
40	 * by the browse-grid card and the master list row so the two never drift. The
41	 * name renders as plain text (never an `<h4>`), so only the detail panel owns
42	 * the suite heading. `description` is opt-in (the grid card shows it; the row
43	 * doesn't).
44	 */
45	function SuiteIdentity({
46	  suite,
47	  conn,
48	  size = 40,
49	  selected = false,
50	  showDescription = false,
51	}: {
52	  suite: Suite;
53	  conn: Connection | undefined;
54	  size?: number;
55	  selected?: boolean;
56	  showDescription?: boolean;
57	}) {
58	  return (
59	    <Flex
60	      gap={12}
61	      align={showDescription ? 'flex-start' : 'center'}
62	      style={{ width: '100%', minWidth: 0 }}
63	    >
64	      {conn && <ConnectionTypeAvatar type={conn.type} size={size} />}
65	      <Flex vertical gap={2} style={{ minWidth: 0, flex: 1 }}>
66	        <Typography.Text strong ellipsis style={selected ? { color: BRAND.primary } : undefined}>
67	          {suite.name}
68	        </Typography.Text>
69	        {conn ? (
70	          <Flex gap={6} align="center">
71	            <Typography.Text type="secondary" style={{ fontSize: 12 }} ellipsis>
72	              {conn.name}
73	            </Typography.Text>
74	            <Tag color={ENV_COLORS[conn.env]} style={{ marginInlineEnd: 0 }}>
75	              {envLabel(conn.env)}
76	            </Tag>
77	          </Flex>
78	        ) : (
79	          <Typography.Text type="secondary" style={{ fontSize: 12 }}>
80	            No connection
81	          </Typography.Text>
82	        )}
83	        {showDescription && suite.description && (
84	          <Typography.Paragraph
85	            type="secondary"
86	            ellipsis={{ rows: 2 }}
87	            style={{ fontSize: 12, margin: 0, marginTop: 2 }}
88	          >
89	            {suite.description}
90	          </Typography.Paragraph>
91	        )}
92	      </Flex>
93	    </Flex>
94	  );
95	}
96	
97	export function Suites() {
98	  const navigate = useNavigate();
99	  // The selected suite is the route (`/suites/:suiteId`) so it deep-links and
100	  // survives the round-trip to the check editor; `/suites` selects nothing.
101	  const { suiteId } = useParams<{ suiteId: string }>();
102	  const selectedId = suiteId ?? null;
103	  const { state, reload } = useAsyncData(listSuites);
104	  const { state: connState } = useAsyncData(listConnections);
105	  // `drawer.suite === undefined` while open = create mode; a suite = edit.
106	  const [drawer, setDrawer] = useState<{ open: boolean; suite?: Suite }>({ open: false });
107	  const [importOpen, setImportOpen] = useState(false);
108	
109	  const connections = connState.status === 'ok' ? connState.data : [];
110	  // A suite binds to a datasource only — creating/importing needs at least one
111	  // (orchestration providers don't count; CLAUDE.md §4, #242).
112	  const hasDatasource = connections.some((c) => CONNECTION_KIND[c.type] === 'datasource');
113	
114	  return (
115	    <Flex vertical gap={24}>
116	      <Flex justify="space-between" align="center" gap={12}>
117	        <Typography.Title level={3} style={{ margin: 0 }}>
118	          Suites
119	        </Typography.Title>
120	        <Flex gap={8}>
121	          <Button
122	            loading={connState.status === 'loading'}
123	            disabled={!hasDatasource}
124	            onClick={() => setImportOpen(true)}
125	          >
126	            Import
127	          </Button>
128	          <Button
129	            type="primary"
130	            loading={connState.status === 'loading'}
131	            disabled={!hasDatasource}
132	            onClick={() => setDrawer({ open: true })}
133	          >
134	            New suite
135	          </Button>
136	        </Flex>
137	      </Flex>
138	      {connState.status === 'error' && (
139	        // Suites can still be viewed/deleted, but creating one needs the
140	        // connection list — surface the failure rather than silently disabling.
141	        <Alert
142	          type="warning"
143	          showIcon
144	          title="Couldn’t load connections"
145	          description={`Creating a suite is unavailable until connections load. ${connState.error}`}
146	        />
147	      )}
148	      <SuitesBody
149	        state={state}
150	        connections={connections}
151	        selectedId={selectedId}
152	        onSelect={(id) => navigate(`/suites/${id}`)}
153	        onEdit={(suite) => setDrawer({ open: true, suite })}
154	        onDeleted={() => {
155	          navigate('/suites');
156	          reload();
157	        }}
158	      />
159	      <SuiteDrawer
160	        open={drawer.open}
161	        suite={drawer.suite}
162	        connections={connections}
163	        onClose={() => setDrawer({ open: false })}
164	        onSaved={() => {
165	          setDrawer({ open: false });
166	          reload();
167	        }}
168	      />
169	      <ImportSuiteDrawer
170	        open={importOpen}
171	        connections={connections}
172	        onClose={() => setImportOpen(false)}
173	        onImported={(suite) => {
174	          setImportOpen(false);
175	          reload();
176	          navigate(`/suites/${suite.id}`);
177	        }}
178	      />
179	    </Flex>
180	  );
181	}
182	
183	function SuitesBody({
184	  state,
185	  connections,
186	  selectedId,
187	  onSelect,
188	  onEdit,
189	  onDeleted,
190	}: {
191	  state: AsyncState<Suite[]>;
192	  connections: Connection[];
193	  selectedId: string | null;
194	  onSelect: (id: string) => void;
195	  onEdit: (suite: Suite) => void;
196	  onDeleted: () => void;
197	}) {
198	  if (state.status === 'loading') {
199	    return <Spin tip="Loading suites…" size="large" style={{ marginTop: 80 }} />;
200	  }
201	  if (state.status === 'error') {
202	    return (
203	      <Alert
204	        type="error"
205	        showIcon
206	        title="Failed to load suites"
207	        description={state.error}
208	        style={{ margin: 24 }}
209	      />
210	    );
211	  }
212	  const suites = state.data;
213	  if (suites.length === 0) {
214	    return <Empty description="No suites yet — create one to start authoring checks." />;
215	  }
216	  const selected = suites.find((s) => s.id === selectedId) ?? null;
217	
