{"method":"get_file","path":"templates/app/SuiteFlow.jsx","content":"// DataQ — New Suite (full-page). Mirrors the Figma "new suite details /
// source" frame: name + description, datasource connection, target dataset,
// schedule. On create, continues to Define Rules (Add Check). Exports
// window.NewSuiteScreen.
const DQsuite = window.DataQDesignSystem_317fec;

const CONNECTIONS = [
  'Snowflake_Prod_01', 'AWS_S3_Landing', 'Databricks_UC_Main',
  'Postgres_EU_West', 'ADLS_Gen2_Archive',
];

function NewSuiteScreen({ go }) {
  const { Card, Button, Input, Select } = DQsuite;
  const { PageHeader } = window;
  const [conn, setConn] = React.useState(CONNECTIONS[0]);
  const [schedule, setSchedule] = React.useState('Hourly');
  const [name, setName] = React.useState('');

  return (
    <div style={{ maxWidth: 720, margin: '0 auto' }}>
      <PageHeader backLabel="Suites" onBack={() => go('suites')}
        title="New Suite" subtitle="Define a validation suite, then add checks" />
      <Card padding={24}>
        <div style={{ display: 'flex', flexDirection: 'column', gap: 16 }}>
          <Input label="Suite name" placeholder="Daily Revenue Audit" value={name} onChange={(e) => setName(e.target.value)} />
          <Input label="Description (optional)" placeholder="What this suite validates and why." />

          <div style={{ height: 1, background: 'var(--divider)', margin: '2px 0' }} />
          <div style={{ fontSize: 12, fontWeight: 600, letterSpacing: '.04em', textTransform: 'uppercase', color: 'var(--text-muted)' }}>Source</div>

          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
            <Select label="Connection" options={CONNECTIONS} value={conn} onChange={(e) => setConn(e.target.value)}
              hint="Pick from your configured datasources." />
            <Select label="Schedule" value={schedule} onChange={(e) => setSchedule(e.target.value)}
              options={['On data arrival', 'Hourly', 'Daily 02:00', 'Weekly (Mon)', 'Manual only']}
              hint="Or trigger from an ADF / Airflow run." />
          </div>
          <Input label="Dataset / table" placeholder="prod.analytics.fct_revenue" mono
            hint="Fully-qualified table, file glob, or view the suite runs against." />
        </div>

        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 10, marginTop: 24, paddingTop: 20, borderTop: '1px solid var(--divider)' }}>
          <span style={{ fontSize: 13, color: 'var(--text-muted)' }}>Next: define the suite's checks.</span>
          <div style={{ display: 'flex', gap: 10 }}>
            <Button variant="secondary" onClick={() => go('suites')}>Cancel</Button>
            <Button variant="primary" onClick={() => go('suite-check', { suiteName: name || 'New Suite' })}>Create &amp; Add Checks</Button>
          </div>
        </div>
      </Card>
    </div>
  );
}

