      )}
    </Flex>
  );
}

function TypeSection({
  kind,
  types,
  onPick,
}: {
  kind: ConnectionKind;
  types: ConnectionType[];
  onPick: (type: ConnectionType) => void;
}) {
  return (
    <Flex vertical gap={12}>
