      <Flex wrap gap={12}>
        {types.map((type) => (
          <Card
            key={type}
            hoverable
            size="small"
            style={{ minWidth: 200 }}
            onClick={() => onPick(type)}
          >
            <Typography.Text strong>{CONNECTION_TYPE_LABELS[type]}</Typography.Text>
          </Card>
        ))}
      </Flex>
    </Flex>
  );
}

