      {backLabel && (
        <button onClick={onBack} style={{
          display: 'inline-flex', alignItems: 'center', gap: 6, background: 'none', border: 'none', cursor: 'pointer',
          padding: '2px 2px 8px', color: 'var(--text-secondary)', fontFamily: 'var(--font-sans)', fontSize: 13, fontWeight: 500,
        }}>
          <window.Icon.chevronLeft size={15} /> {backLabel}
        </button>
      )}
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', gap: 16 }}>
        <div>
          <h1 style={{ margin: 0, fontSize: 24, fontWeight: 600, color: 'var(--text-primary)', letterSpacing: '-0.005em' }}>{title}</h1>
          {subtitle && <div style={{ fontSize: 14, color: 'var(--text-secondary)', marginTop: 4 }}>{subtitle}</div>}
        </div>
        {actions && <div style={{ display: 'flex', gap: 8, flex: 'none' }}>{actions}</div>}
      </div>
    </div>
  );
}

function NavItem({ item, active, onClick }) {
  const [hover, setHover] = React.useState(false);
  const I = window.Icon[item.icon];
  return (
    <button
      onClick={onClick}
      onMouseEnter={() => setHover(true)}
      onMouseLeave={() => setHover(false)}
      style={{
        display: 'flex', alignItems: 'center', gap: 12, width: '100%',
        height: 'var(--menu-item-height)', padding: '0 12px', margin: 0,
        border: 'none', borderRadius: 'var(--radius)', cursor: 'pointer', textAlign: 'left',
        fontFamily: 'var(--font-sans)', fontSize: 14, fontWeight: active ? 600 : 500,
        color: active ? 'var(--indigo-600)' : 'var(--text-body)',
        background: active ? 'var(--bg-selected)' : hover ? 'var(--bg-hover)' : 'transparent',
        transition: 'background .15s, color .15s',
      }}
    >
      <span style={{ color: active ? 'var(--indigo-600)' : 'var(--gray-500)', display: 'inline-flex' }}><I size={18} /></span>
      {item.label}
    </button>
  );
}

function Sidebar({ route, go }) {
  const section = SECTION[route] || route;
  return (
    <aside style={{
      width: 'var(--sidebar-width)', flex: 'none', background: 'var(--bg-sider)',
      borderRight: '1px solid var(--border)', display: 'flex', flexDirection: 'column',
      height: '100%', boxSizing: 'border-box', paddingTop: 8,
    }}>
      <nav style={{ display: 'flex', flexDirection: 'column', gap: 4, padding: '8px' }}>
        {NAV.map((n) => <NavItem key={n.key} item={n} active={section === n.key} onClick={() => go(n.key)} />)}
      </nav>
      <div style={{ flex: 1 }} />
      <div style={{ padding: '8px', display: 'flex', flexDirection: 'column', gap: 4, borderTop: '1px solid var(--divider)' }}>
        <NavItem item={{ label: 'Admin', icon: 'shield' }} active={section === 'admin'} onClick={() => go('admin')} />
        <NavItem item={{ label: 'Settings', icon: 'settings' }} active={section === 'settings'} onClick={() => go('settings')} />
        <NavItem item={{ label: 'Documentation', icon: 'docs' }} onClick={() => {}} />
      </div>
    </aside>
  );
}

function UserMenu({ role, setRole }) {
  const [open, setOpen] = React.useState(false);
  const roles = ['Admin', 'Viewer'];
  return (
    <div style={{ position: 'relative' }}>
      <button
        onClick={() => setOpen((o) => !o)}
        style={{ display: 'flex', alignItems: 'center', gap: 8, background: 'none', border: 'none', cursor: 'pointer', padding: '4px 6px', borderRadius: 'var(--radius)' }}
      >
        <Avatar name="Jane Doe" size={28} />
        <span style={{ fontSize: 14, color: 'var(--text-primary)' }}>Jane Doe</span>
        <span style={{ color: 'var(--gray-500)', display: 'inline-flex' }}><window.Icon.chevronRight size={12} style={{ transform: 'rotate(90deg)' }} /></span>
      </button>
      {open && (
        <div style={{
          position: 'absolute', right: 0, top: 'calc(100% + 6px)', width: 232, zIndex: 20,
          background: 'var(--bg-card)', borderRadius: 'var(--radius-lg)', boxShadow: 'var(--shadow-overlay)',
          border: '1px solid var(--border)', padding: 6,
        }}>
          <div style={{ padding: '8px 10px' }}>
            <div style={{ fontSize: 14, fontWeight: 600, color: 'var(--text-primary)' }}>Jane Doe</div>
            <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>jane.doe@acme.com</div>
          </div>
          <div style={{ height: 1, background: 'var(--divider)', margin: '4px 0' }} />
          <div style={{ padding: '8px 10px' }}>
            <div style={{ fontSize: 11, fontWeight: 600, letterSpacing: '.05em', textTransform: 'uppercase', color: 'var(--text-muted)', marginBottom: 8 }}>View as (demo)</div>
            <div style={{ display: 'flex', gap: 4 }}>
              {roles.map((r) => (
                <button key={r} onClick={() => { setRole && setRole(r); }} style={{
                  flex: 1, height: 28, border: '1px solid var(--border)', borderRadius: 'var(--radius)', cursor: 'pointer',
                  fontFamily: 'var(--font-sans)', fontSize: 13, fontWeight: 600,
                  background: role === r ? 'var(--bg-selected)' : 'transparent',
                  color: role === r ? 'var(--indigo-600)' : 'var(--text-body)',
                  borderColor: role === r ? 'var(--indigo-200)' : 'var(--border)',
                }}>{r}</button>
              ))}
            </div>
          </div>
          <div style={{ height: 1, background: 'var(--divider)', margin: '4px 0' }} />
          <button style={{ display: 'flex', width: '100%', padding: '8px 10px', background: 'none', border: 'none', borderRadius: 'var(--radius)', cursor: 'pointer', fontSize: 14, color: 'var(--text-muted)', textAlign: 'left' }}>Sign out</button>
        </div>
      )}
    </div>
  );
}

function Header({ role, setRole }) {
  return (
    <header style={{
      display: 'flex', alignItems: 'center', gap: 16, padding: '0 24px',
      height: 'var(--header-height)', flex: 'none',
      background: 'var(--bg-header)', borderBottom: '1px solid var(--border)',
    }}>
      <div style={{ flex: 1, display: 'flex', alignItems: 'center', gap: 10 }}>
        <img src="../../assets/logo/dataq-mark.svg" width="28" height="28" alt="" />
        <span style={{ fontFamily: 'var(--font-sans)', fontWeight: 700, fontSize: 17, color: 'var(--ink)', letterSpacing: '-0.01em' }}>DataQ</span>
      </div>
      <UserMenu role={role} setRole={setRole} />
    </header>
  );
}

function Watermark() {
  return (
    <div aria-hidden style={{ position: 'absolute', inset: 0, overflow: 'hidden', pointerEvents: 'none' }}>
      <img src="../../assets/logo/dataq-mark.svg" style={{ position: 'absolute', right: -90, bottom: -90, width: 360, opacity: 0.05 }} alt="" />
    </div>
  );
}

function AppShell({ route, go, role, setRole, children }) {
  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100vh', background: 'var(--bg-app)', overflow: 'hidden' }}>
      <Header role={role} setRole={setRole} />
      <div style={{ flex: 1, display: 'flex', minHeight: 0 }}>
        <Sidebar route={route} go={go} />
        <main style={{ flex: 1, overflowY: 'auto', position: 'relative', minWidth: 0 }}>
          <Watermark />
          <div style={{ position: 'relative', padding: 24 }}>{children}</div>
        </main>
      </div>
    </div>
  );
}

Object.assign(window, { AppShell, PageHeader });
