{"method":"get_file","path":"templates/app/ConnectionsScreen.jsx","content":"// DataQ — Connections page. A grid of datasource connection cards with
// the real per-source brand accents (connectionVisuals.tsx), env tag and
// status. Composes Card, StatusBadge, Tag, Button.
const DQc = window.DataQDesignSystem_317fec;

// type → { icon, accent var, glyph } mirroring connectionVisuals.tsx
const SOURCES = {
  snowflake:     { icon: 'cloud',    accent: 'var(--src-snowflake)' },
  adls_gen2:     { icon: 'database', accent: 'var(--src-adls)' },
  s3:            { icon: 'database', accent: 'var(--src-s3)' },
  unity_catalog: { icon: 'layers',  accent: 'var(--src-unity-catalog)' },
  adf:           { icon: 'orchestration', accent: 'var(--src-adf)' },
  airflow:       { icon: 'airflow', accent: 'var(--src-airflow)' },
};

const KIND = { adf: 'Orchestration', airflow: 'Orchestration' };

const CONNECTIONS = [
  { name: 'ADF_Prod_Orchestrator', type: 'adf', label: 'Azure Data Factory', env: 'PROD', status: 'healthy', sync: '1m ago' },
  { name: 'Airflow_Analytics', type: 'airflow', label: 'Apache Airflow', env: 'PROD', status: 'healthy', sync: '4m ago' },
  { name: 'Snowflake_Prod_01', type: 'snowflake', label: 'Snowflake', env: 'PROD', status: 'healthy', sync: '2m ago' },
  { name: 'AWS_S3_Landing', type: 's3', label: 'AWS S3', env: 'PROD', status: 'healthy', sync: '5m ago' },
  { name: 'Databricks_UC_Main', type: 'unity_catalog', label: 'Unity Catalog', env: 'UAT', status: 'warn', sync: '18m ago' },
  { name: 'ADLS_Gen2_Archive', type: 'adls_gen2', label: 'ADLS Gen2', env: 'DEV', status: 'failed', sync: '3h ago' },
];

function ConnectionCard({ c }) {
  const { Card, StatusBadge, Tag } = DQc;
  const src = SOURCES[c.type];
  const I = window.Icon[src.icon];
  return (
    <Card interactive padding={20}>
      <div style={{ display: 'flex', alignItems: 'flex-start', justifyContent: 'space-between' }}>
        <div style={{
          width: 44, height: 44, borderRadius: 10, flex: 'none',
          background: `color-mix(in srgb, ${src.accent} 12%, #fff)`, color: src.accent,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}><I size={22} /></div>
