function SourceSection({
  group,
  onPick,
}: {
  group: SourceGroup;
  onPick: (type: ConnectionType) => void;
}) {
  return (
    <Flex vertical gap={group.note ? 6 : 12}>
      <Typography.Text
        type="secondary"
        strong
        style={{ fontSize: 12, letterSpacing: '0.05em', textTransform: 'uppercase' }}
