      </Typography.Text>
      {group.note && (
        <Typography.Text type="secondary" style={{ maxWidth: 560 }}>
          {group.note}
        </Typography.Text>
      )}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
